export const getUpdateProfileUrl = () => {
  return `/api/profile`;
};

export const updateProfile = async (
  updateProfileRequest: UpdateProfileRequest,
  options?: RequestInit,
): Promise<Profile> => {
  return customFetch<Profile>(getUpdateProfileUrl(), {
    ...options,
    method: "PATCH",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(updateProfileRequest),
  });
};

export const getUpdateProfileMutationOptions = <
  TError = ErrorType<Error>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateProfile>>,
    TError,
    { data: BodyType<UpdateProfileRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateProfile>>,
  TError,
  { data: BodyType<UpdateProfileRequest> },
  TContext
> => {
  const mutationKey = ["updateProfile"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateProfile>>,
    { data: BodyType<UpdateProfileRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return updateProfile(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateProfileMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateProfile>>
>;
export type UpdateProfileMutationBody = BodyType<UpdateProfileRequest>;
export type UpdateProfileMutationError = ErrorType<Error>;

/**
 * @summary Update current user profile
 */
export const useUpdateProfile = <
  TError = ErrorType<Error>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateProfile>>,
    TError,
    { data: BodyType<UpdateProfileRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updateProfile>>,
  TError,
  { data: BodyType<UpdateProfileRequest> },
  TContext
> => {
  return useMutation(getUpdateProfileMutationOptions(options));
};

/**
 * @summary Get all posts by the current user
 */
export const getGetMyPostsUrl = () => {
  return `/api/profile/posts`;
};

export const getMyPosts = async (
  options?: RequestInit,
): Promise<PostsResponse> => {
  return customFetch<PostsResponse>(getGetMyPostsUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetMyPostsQueryKey = () => {
  return [`/api/profile/posts`] as const;
};

export const getGetMyPostsQueryOptions = <
  TData = Awaited<ReturnType<typeof getMyPosts>>,
  TError = ErrorType<Error>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getMyPosts>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetMyPostsQueryKey();

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getMyPosts>>> = ({
    signal,
  }) => getMyPosts({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getMyPosts>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetMyPostsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getMyPosts>>
>;
export type GetMyPostsQueryError = ErrorType<Error>;

/**
 * @summary Get all posts by the current user
 */

export function useGetMyPosts<
  TData = Awaited<ReturnType<typeof getMyPosts>>,
  TError = ErrorType<Error>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getMyPosts>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetMyPostsQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
